package main

import "fmt"

func main() {
	target := 67 // Sabit hedef sayi (demo amacli)

	fmt.Println("Sayi tahmin oyunu basladi! (1-100 arasi)")
	fmt.Println("(Bu demo, onceden belirlenmis tahminlerle calisir)\n")

	guesses := []int{50, 75, 62, 68, 65, 67}
	found := false

	for _, guess := range guesses {
		fmt.Println("Tahmin:", guess)

		if guess == target {
			fmt.Println("Tebrikler! Dogru tahmin:", target)
			found = true
			break
		} else if guess < target {
			fmt.Println("Daha buyuk bir sayi dene.\n")
		} else {
			fmt.Println("Daha kucuk bir sayi dene.\n")
		}
	}

	if !found {
		fmt.Println("\nTahmin edilemedi. Dogru sayi:", target)
	}

	fmt.Println("\nToplam deneme sayisi:", len(guesses))
}
